346 /// Conservatively clears subclassOptionalData after a reassociation or
347 /// commutation. We preserve fast-math flags when applicable as they can be
348 /// preserved.
349 static void ClearSubclassDataAfterReassociation(BinaryOperator &I) {
350   FPMathOperator *FPMO = dyn_cast<FPMathOperator>(&I);
351   if (!FPMO) {
352     I.clearSubclassOptionalData();
353     return;
